#!/bin/bash
whois "$1" | awk -F': ' '{gsub(/^[ \t]+|[ \t]+$/,"",$1);gsub(/^[ \t]+|[ \t]+$/,"",$2);k=$1;v=$2;if(k=="Registrant Name")r1=v;if(k=="Registrant Organization")r2=v;if(k=="Registrant Street")r3=v" ";if(k=="Registrant City")r4=v;if(k=="Registrant State/Province")r5=v;if(k=="Registrant Postal Code")r6=v;if(k=="Registrant Country")r7=v;if(k=="Registrant Phone")r8=v;if(k=="Registrant Phone Ext")r9=v;if(k=="Registrant Fax")r10=v;if(k=="Registrant Fax Ext")r11=v;if(k=="Registrant Email")r12=v;if(k=="Admin Name")a1=v;if(k=="Admin Organization")a2=v;if(k=="Admin Street")a3=v" ";if(k=="Admin City")a4=v;if(k=="Admin State/Province")a5=v;if(k=="Admin Postal Code")a6=v;if(k=="Admin Country")a7=v;if(k=="Admin Phone")a8=v;if(k=="Admin Phone Ext")a9=v;if(k=="Admin Fax")a10=v;if(k=="Admin Fax Ext")a11=v;if(k=="Admin Email")a12=v;if(k=="Tech Name")t1=v;if(k=="Tech Organization")t2=v;if(k=="Tech Street")t3=v" ";if(k=="Tech City")t4=v;if(k=="Tech State/Province")t5=v;if(k=="Tech Postal Code")t6=v;if(k=="Tech Country")t7=v;if(k=="Tech Phone")t8=v;if(k=="Tech Phone Ext")t9=v;if(k=="Tech Fax")t10=v;if(k=="Tech Fax Ext")t11=v;if(k=="Tech Email")t12=v}END{printf "Registrant Name,%s\nRegistrant Organization,%s\nRegistrant Street,%s\nRegistrant City,%s\nRegistrant State/Province,%s\nRegistrant Postal Code,%s\nRegistrant Country,%s\nRegistrant Phone,%s\nRegistrant Phone Ext:,%s\nRegistrant Fax,%s\nRegistrant Fax Ext:,%s\nRegistrant Email,%s\nAdmin Name,%s\nAdmin Organization,%s\nAdmin Street,%s\nAdmin City,%s\nAdmin State/Province,%s\nAdmin Postal Code,%s\nAdmin Country,%s\nAdmin Phone,%s\nAdmin Phone Ext:,%s\nAdmin Fax,%s\nAdmin Fax Ext:,%s\nAdmin Email,%s\nTech Name,%s\nTech Organization,%s\nTech Street,%s\nTech City,%s\nTech State/Province,%s\nTech Postal Code,%s\nTech Country,%s\nTech Phone,%s\nTech Phone Ext:,%s\nTech Fax,%s\nTech Fax Ext:,%s\nTech Email,%s",r1,r2,r3,r4,r5,r6,r7,r8,r9,r10,r11,r12,a1,a2,a3,a4,a5,a6,a7,a8,a9,a10,a11,a12,t1,t2,t3,t4,t5,t6,t7,t8,t9,t10,t11,t12}' > "$1.csv"
